{
  "executive_summary": "A real-time courier bidding system built around Redis-backed atomic job claiming, WebSocket fan-out for courier notifications, and a timer-driven fallback assignment. The architecture centers on a Bid Window lifecycle managed in Redis with Lua-script atomicity guaranteeing exactly-one-winner semantics, a WebSocket gateway maintaining persistent connections to courier apps, and a sorted-set-based timer service for reliable 15-second expiry with auto-assignment. At 500 concurrent bid windows × 30 couriers/zone, the system handles ~15,000 concurrent WebSocket connections and a peak of ~1,000 claim attempts/second — well within single-Redis-node capacity.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingress Service",
        "responsibility": "Receives new orders from the marketplace, validates them, and publishes an OrderPlaced domain event to the message bus. Stateless, horizontally scalable.",
        "boundaries": "Owns order validation and initial persistence. Does NOT decide courier eligibility or manage bid windows."
      },
      {
        "name": "Bid Window Manager",
        "responsibility": "Reacts to OrderPlaced events. Queries Courier Eligibility for the target zone, creates a BidWindow record in Redis (state=OPEN, TTL metadata, eligible courier list), registers a 15-second timer, and instructs the WebSocket Gateway to fan out the job offer. Owns the full bid window lifecycle: OPEN → CLAIMED | EXPIRED → ASSIGNED.",
        "boundaries": "Owns bid window state machine. Does not own courier profiles or order data beyond what's needed for the offer payload."
      },
      {
        "name": "Claim Processor",
        "responsibility": "Receives courier accept attempts from the WebSocket Gateway. Executes an atomic Redis Lua script to attempt claiming the bid window. On success: publishes JobClaimed event, notifies winner and losers via WebSocket Gateway, cancels the expiry timer. On failure: returns 'already claimed' to the courier.",
        "boundaries": "Owns the atomic claim operation ONLY. Does not manage timers or courier eligibility."
      },
      {
        "name": "Timer Service",
        "responsibility": "Manages 15-second expiry timers using a Redis sorted set (score = expiry timestamp). A polling loop checks for expired entries every 200ms. On expiry: publishes BidWindowExpired event, triggering auto-assignment to the highest-rated eligible courier who hasn't declined.",
        "boundaries": "Owns timer lifecycle. Does not own assignment logic — delegates to Claim Processor for the auto-assignment claim attempt."
      },
      {
        "name": "Courier Eligibility Service",
        "responsibility": "Given a zone and order attributes, returns the ranked list of eligible couriers (online, in-zone, not already on a job, meets vehicle/capacity requirements). Maintains a real-time view of courier availability via heartbeats.",
        "boundaries": "Owns courier availability and eligibility rules. Does not own courier profiles (reads from Courier Profile Service)."
      },
      {
        "name": "WebSocket Gateway",
        "responsibility": "Maintains persistent WebSocket connections to courier mobile apps. Handles fan-out of job offers to eligible couriers, relays accept/decline messages to the Claim Processor, and pushes outcome notifications (won/lost/expired). Supports channel-based pub/sub for targeting specific courier groups.",
        "boundaries": "Owns transport layer only. Stateless regarding business logic — acts as a message relay. Scales horizontally with sticky sessions or Redis pub/sub for cross-node fan-out."
      },
      {
        "name": "Auto-Assignment Handler",
        "responsibility": "Reacts to BidWindowExpired events. Reads the eligible courier list (pre-sorted by rating), iterates through candidates, and issues a claim on behalf of the highest-rated available courier. If all decline or are unavailable, escalates to a manual dispatch queue.",
        "boundaries": "Owns fallback assignment strategy. Uses the same atomic claim path as courier-initiated accepts."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingress Service",
        "to": "Bid Window Manager",
        "contract": "OrderPlaced event: { orderId, zone, pickupLocation, dropoffLocation, orderAttributes, timestamp }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Bid Window Manager",
        "to": "Courier Eligibility Service",
        "contract": "GET /eligible-couriers?zone={zone}&attributes={attrs} → { couriers: [{ courierId, rating, location }] }",
        "coupling_type": "synchronous request-response (moderate)"
      },
      {
        "from": "Bid Window Manager",
        "to": "WebSocket Gateway",
        "contract": "FanOutJobOffer command via internal message bus: { bidWindowId, courierIds[], offerPayload }",
        "coupling_type": "command (async, loose)"
      },
      {
        "from": "WebSocket Gateway",
        "to": "Claim Processor",
        "contract": "CourierAccept message: { bidWindowId, courierId, timestamp }",
        "coupling_type": "command (async, loose)"
      },
      {
        "from": "Claim Processor",
        "to": "WebSocket Gateway",
        "contract": "ClaimResult notification: { bidWindowId, winnerId, status: 'claimed'|'already_claimed' } + LosersNotification: { bidWindowId, courierIds[], status: 'job_taken' }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Bid Window Manager",
        "to": "Timer Service",
        "contract": "RegisterTimer command: { bidWindowId, expiresAt: now+15s }",
        "coupling_type": "command (async, loose)"
      },
      {
        "from": "Timer Service",
        "to": "Auto-Assignment Handler",
        "contract": "BidWindowExpired event: { bidWindowId, eligibleCouriers[], orderId }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Auto-Assignment Handler",
        "to": "Claim Processor",
        "contract": "Same CourierAccept message but with source: 'auto-assign'",
        "coupling_type": "command (async, loose)"
      }
    ],
    "data_flow": "1) Order Ingress publishes OrderPlaced → 2) Bid Window Manager consumes event, queries Courier Eligibility for ranked courier list, creates Redis key `bid:{windowId}` with value `{state: OPEN, eligibleCouriers: [...], orderId}` → 3) Registers timer in Redis sorted set `bid:timers` with score = expiry epoch ms → 4) Sends FanOutJobOffer to WebSocket Gateway → 5) Gateway pushes offer to all eligible couriers' WebSocket connections → 6) Courier taps Accept → Gateway relays CourierAccept to Claim Processor → 7) Claim Processor executes Lua script: `if bid.state == OPEN then set state=CLAIMED, winnerId=courierId, return SUCCESS else return ALREADY_CLAIMED` → 8a) On SUCCESS: publish JobClaimed event, notify winner + losers via Gateway, cancel timer → 8b) On ALREADY_CLAIMED: return rejection to courier → 9) If timer fires before any claim: Timer Service publishes BidWindowExpired → Auto-Assignment Handler claims on behalf of highest-rated courier using same atomic Lua script path.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Swap via Redis Lua Script",
        "rationale": "Redis Lua scripts execute atomically (single-threaded). This guarantees exactly-one-winner without distributed locks, two-phase commits, or database-level pessimistic locking. At our scale (~1,000 claim attempts/second peak), a single Redis node handles this trivially with sub-millisecond latency."
      },
      {
        "pattern": "Event-Driven Architecture with Command Segregation",
        "rationale": "Decouples order placement from bid window management from claim processing. Each component reacts to events independently, enabling horizontal scaling of each tier. Commands (FanOutJobOffer, RegisterTimer) are used where ordering matters; events (OrderPlaced, JobClaimed) where fan-out or eventual consistency is acceptable."
      },
      {
        "pattern": "Polling-based Timer with Redis Sorted Set",
        "rationale": "More reliable than Redis key expiry notifications (which are best-effort and can be missed under load). Sorted set with expiry timestamps, polled every 200ms by the Timer Service, guarantees timely expiry detection with at-most 200ms jitter — acceptable for a 15-second window. Simpler and more debuggable than a distributed scheduler."
      },
      {
        "pattern": "WebSocket Gateway with Pub/Sub Fan-out",
        "rationale": "Mobile couriers need real-time push. WebSocket is the standard for bidirectional real-time communication on mobile. Using Redis pub/sub behind the Gateway allows horizontal scaling — any Gateway node can publish to a channel, and all nodes subscribing to that channel relay to their connected couriers."
      },
      {
        "pattern": "Idempotent Claim Processing",
        "rationale": "Mobile networks are unreliable. A courier might tap Accept twice, or the message might be retried. The Lua script is inherently idempotent — a second claim attempt for the same courier on an already-claimed window returns the same result. Claim messages carry a unique requestId for deduplication at the gateway level."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding",
        "classification": "core",
        "aggregates": [
          {
            "name": "BidWindow",
            "root_entity": "BidWindow",
            "invariants": [
              "A BidWindow can only transition OPEN → CLAIMED or OPEN → EXPIRED (never backwards, never CLAIMED → EXPIRED)",
              "Exactly one courier can be assigned as winner per BidWindow",
              "A BidWindow must have at least one eligible courier",
              "The 15-second TTL is immutable once set"
            ],
            "state_machine": "OPEN → CLAIMED (via courier accept or auto-assign) | OPEN → EXPIRED (via timer) | EXPIRED → ASSIGNED (via auto-assign handler)"
          }
        ]
      },
      {
        "name": "Courier Availability",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "CourierPresence",
            "root_entity": "CourierPresence",
            "invariants": [
              "A courier is either ONLINE or OFFLINE based on heartbeat recency (stale after 30s)",
              "A courier can only be in one zone at a time",
              "A courier on an active job is not eligible for new bids"
            ]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root_entity": "Order",
            "invariants": [
              "An order transitions PLACED → BIDDING → ASSIGNED → IN_TRANSIT → DELIVERED",
              "An order in BIDDING state has exactly one active BidWindow"
            ]
          }
        ]
      },
      {
        "name": "Courier Profile",
        "classification": "generic",
        "aggregates": [
          {
            "name": "CourierProfile",
            "root_entity": "CourierProfile",
            "invariants": [
              "Rating is a rolling average updated after each delivery"
            ]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier: Order Management publishes OrderPlaced; Bidding consumes it. Bidding publishes JobClaimed/JobAssigned back upstream so Order can transition to ASSIGNED."
      },
      {
        "upstream": "Courier Availability",
        "downstream": "Bidding",
        "relationship": "Conformist: Bidding queries Courier Availability for eligible couriers and conforms to its model of presence and zone membership."
      },
      {
        "upstream": "Courier Profile",
        "downstream": "Courier Availability",
        "relationship": "Anti-Corruption Layer: Courier Availability reads ratings from Courier Profile but translates into its own eligibility model, insulating bidding logic from profile schema changes."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Redis as the single source of truth for bid window state (not a relational database)",
      "gains": "Sub-millisecond atomic operations via Lua scripts. No distributed lock coordination. Extremely simple concurrency model. Handles 500 concurrent windows trivially (tiny memory footprint).",
      "sacrifices": "Redis is not durable by default — if it crashes mid-bid, open windows are lost. Mitigated by AOF persistence with fsync every second (max 1s data loss) and by the short 15-second window lifetime (most state is ephemeral). No complex query capability.",
      "alternatives_considered": [
        "PostgreSQL with SELECT FOR UPDATE — durable but adds 5-10ms latency per claim and creates lock contention under concurrent accepts",
        "DynamoDB conditional writes — viable but adds network hop latency and cost for what is fundamentally an in-memory problem",
        "Application-level mutex — does not work across multiple service instances"
      ]
    },
    {
      "decision": "Polling-based timer (200ms interval) instead of Redis keyspace notifications or external scheduler",
      "gains": "Deterministic, debuggable, reliable. No missed expirations. Simple to monitor (just check the sorted set size). 200ms jitter is negligible on a 15-second window.",
      "sacrifices": "Slightly higher Redis load from polling (ZRANGEBYSCORE every 200ms — trivial). Not truly event-driven for the timer path.",
      "alternatives_considered": [
        "Redis keyspace notifications (CONFIG SET notify-keyspace-events Ex) — documented as best-effort, can miss events under load or during failover",
        "External scheduler (e.g., SQS delay queue, Temporal) — adds infrastructure complexity for a simple timer use case",
        "In-process setTimeout — doesn't survive process restarts, doesn't work across instances"
      ]
    },
    {
      "decision": "Single Redis node for bid state (not a cluster)",
      "gains": "Lua script atomicity is guaranteed on a single node. No cluster-mode Lua restrictions (all keys must hash to same slot). Simpler operations. 500 concurrent windows with ~30 eligible couriers each = ~15,000 keys — trivial for a single node.",
      "sacrifices": "Single point of failure. Mitigated by Redis Sentinel for automatic failover (sub-second). During failover, any in-flight bid windows (up to 500) may need to be re-created — acceptable since the 15-second window can be extended or restarted.",
      "alternatives_considered": [
        "Redis Cluster — adds complexity for Lua scripts (hash slots), not needed at this scale",
        "Multi-region active-active — massive complexity for a 15-second ephemeral window; not justified"
      ]
    },
    {
      "decision": "WebSocket for courier communication (not long-polling or server-sent events)",
      "gains": "Bidirectional real-time communication. Courier can send accept/decline without a new HTTP request. Lower latency than polling. Well-supported on iOS/Android.",
      "sacrifices": "Stateful connections require sticky sessions or cross-node pub/sub. More complex connection lifecycle management (heartbeats, reconnection). Higher memory per connection on Gateway nodes.",
      "alternatives_considered": [
        "Server-Sent Events (SSE) — unidirectional, would still need a separate HTTP endpoint for accepts",
        "Long polling — higher latency, more HTTP overhead, poor fit for 15-second real-time window",
        "Push notifications (APNs/FCM) — too slow (seconds of latency), unreliable for time-critical bidding"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Bid Window Duration",
      "evolution_path": "The 15-second timeout is a configuration value in the Bid Window Manager, not hardcoded. Can be made dynamic per zone, time of day, or order priority without architectural changes."
    },
    {
      "area": "Eligibility Rules",
      "evolution_path": "Courier Eligibility Service is a separate bounded context. Rules can evolve from simple zone-matching to complex ML-based ranking (factoring in distance, historical acceptance rate, estimated arrival time) without touching the bidding core."
    },
    {
      "area": "Auto-Assignment Strategy",
      "evolution_path": "The Auto-Assignment Handler is a separate component with a pluggable strategy. Can evolve from 'highest-rated' to weighted scoring, auction-based pricing, or round-robin fairness algorithms."
    },
    {
      "area": "Bidding Model Evolution",
      "evolution_path": "Current model is first-accept-wins. The BidWindow aggregate can be extended to support competitive bidding (couriers submit price bids, best bid wins at expiry) by changing the state machine without altering the WebSocket Gateway or Timer Service."
    },
    {
      "area": "Scale-Out Path",
      "evolution_path": "If bid volume exceeds single-Redis-node capacity (unlikely below ~50,000 concurrent windows), bid windows can be sharded by zone across multiple Redis instances since zones are natural partition boundaries."
    }
  ],

  "rigidity_points": [
    {
      "area": "Redis Lua Script for Atomic Claiming",
      "reason": "This is the correctness invariant of the entire system. The Lua script MUST remain the single point of claim arbitration. Any bypass (e.g., check-then-set without Lua, or claim logic in application code) breaks the exactly-one-winner guarantee. This is intentionally rigid."
    },
    {
      "area": "BidWindow State Machine Transitions",
      "reason": "OPEN → CLAIMED and OPEN → EXPIRED are the only valid transitions from OPEN. Adding new states or transitions requires careful analysis of race conditions. This rigidity protects system correctness."
    },
    {
      "area": "WebSocket as Transport for Real-Time Bidding",
      "reason": "The 15-second window with sub-second response requirements makes WebSocket (or equivalent persistent connection) non-negotiable. Changing to a request-response model would require fundamental rethinking of the courier app interaction model."
    }
  ],

  "risks": [
    {
      "risk": "Redis failover during active bid windows causes loss of in-flight bids",
      "severity": "high",
      "mitigation": "Use Redis Sentinel with sub-second failover. On failover detection, the Bid Window Manager re-creates any bid windows that were in OPEN state (sourced from the Order Service's BIDDING orders) with adjusted TTLs. Accept this as a rare edge case — the 15-second window naturally limits blast radius."
    },
    {
      "risk": "WebSocket disconnection during the 15-second window causes a courier to miss the offer or their accept to be lost",
      "severity": "high",
      "mitigation": "Implement client-side reconnection with exponential backoff (starting at 100ms). On reconnect, the courier app re-fetches active offers via a REST fallback endpoint. Accept messages include a client-generated idempotency key so retries are safe. The 15-second window provides a generous buffer for reconnection."
    },
    {
      "risk": "Clock skew between Timer Service instances causes premature or late expiry",
      "severity": "medium",
      "mitigation": "Use the Redis server's clock (via TIME command) for all timestamp calculations, not the application server's clock. All timer registrations and checks reference Redis time. NTP synchronization across app servers as defense-in-depth."
    },
    {
      "risk": "Courier Eligibility Service becomes a bottleneck (synchronous call in the bid window creation path)",
      "severity": "medium",
      "mitigation": "Cache eligibility results per zone with a 5-second TTL (courier positions don't change meaningfully in 5 seconds). Circuit breaker on the eligibility call — if it fails, use the last-known eligible courier list for the zone. Consider pre-computing eligibility per zone on a 5-second interval and publishing to Redis."
    },
    {
      "risk": "Hot zone problem — a popular zone has 500+ concurrent orders all targeting the same 30 couriers, flooding their devices",
      "severity": "medium",
      "mitigation": "Rate-limit offers per courier (max N active offers at once). If a courier already has 3 pending offers, skip them for new windows. This prevents notification fatigue and wasted bid window slots."
    },
    {
      "risk": "Auto-assignment cascade failure — all eligible couriers are unavailable when the timer fires",
      "severity": "low",
      "mitigation": "Auto-Assignment Handler iterates through the ranked list attempting claims. If all fail, the order enters a MANUAL_DISPATCH queue monitored by ops. Alert fires if the queue depth exceeds a threshold."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases. Phase 1 (MVP): Build the Redis-backed BidWindow aggregate with Lua script claiming, a simple WebSocket Gateway, and the polling timer. Validate the atomic claim guarantee under load. Phase 2 (Resilience): Add Redis Sentinel, WebSocket reconnection with REST fallback, courier offer rate-limiting, and the eligibility caching layer. Phase 3 (Observability): Add bid window lifecycle metrics (time-to-claim histogram, expiry rate, auto-assignment rate), WebSocket connection health dashboards, and Redis operation latency tracking.",
    "files_to_create_or_modify": [
      "src/bidding/domain/BidWindow.ts — Aggregate root with state machine (OPEN → CLAIMED | EXPIRED → ASSIGNED)",
      "src/bidding/infrastructure/RedisBidWindowRepository.ts — Redis-backed repository with Lua scripts for atomic claim",
      "src/bidding/infrastructure/lua/claim-bid.lua — Atomic Lua script: check state=OPEN, set state=CLAIMED + winnerId, return result",
      "src/bidding/infrastructure/lua/create-bid-window.lua — Atomic creation of bid window key + timer registration",
      "src/bidding/application/BidWindowManager.ts — Orchestrates bid window lifecycle: create, fan-out, handle claim results",
      "src/bidding/application/ClaimProcessor.ts — Handles courier accept attempts, delegates to repository",
      "src/bidding/application/AutoAssignmentHandler.ts — Handles expired bid windows, iterates ranked couriers",
      "src/timer/TimerService.ts — Polls Redis sorted set for expired timers, publishes BidWindowExpired events",
      "src/gateway/WebSocketGateway.ts — Manages courier connections, fan-out, accept relay",
      "src/gateway/CourierConnectionManager.ts — Tracks connected couriers by ID, handles reconnection",
      "src/eligibility/CourierEligibilityService.ts — Zone-based courier filtering and ranking",
      "src/shared/events/BiddingEvents.ts — Event type definitions: OrderPlaced, JobClaimed, BidWindowExpired, JobAssigned"
    ],
    "patterns_to_follow": "Use the BidWindow aggregate as the consistency boundary — all state changes go through it. The Lua script IS the aggregate's persistence-level invariant enforcement. Keep the WebSocket Gateway dumb (no business logic) — it is a transport adapter. Use domain events for all cross-component communication. Make claim processing idempotent by design.",
    "pitfalls_to_avoid": [
      "DO NOT check bid window state in application code then update in a separate Redis call — this creates a race condition. ALL state checks and transitions MUST be in a single Lua script.",
      "DO NOT use Redis key expiry (TTL + keyspace notifications) as the primary timer mechanism — it is documented as best-effort and WILL miss expirations under load or during failover.",
      "DO NOT store bid window state in a relational database for the hot path — the latency and locking overhead are unnecessary for ephemeral 15-second state.",
      "DO NOT fan out offers via push notifications (APNs/FCM) — the latency is too high and delivery is not guaranteed within the 15-second window.",
      "DO NOT allow the WebSocket Gateway to make claim decisions — it must relay to the Claim Processor which uses the authoritative Redis Lua script.",
      "DO NOT use Redis WATCH/MULTI/EXEC for the claim operation — Lua scripts are simpler, faster, and avoid retry loops under contention."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Redis Lua script as the atomic claim mechanism — this is the textbook solution for exactly-once-wins semantics at this scale",
      "WebSocket for real-time courier communication — no viable alternative for sub-second bidirectional mobile communication",
      "Event-driven decoupling between Order Management and Bidding — clear bounded context boundary",
      "Single Redis node sufficiency — 500 concurrent windows is orders of magnitude below Redis capacity limits"
    ],
    "low_confidence_areas": [
      "Optimal polling interval for the timer service (200ms chosen as a balance — may need tuning under production load patterns)",
      "Courier offer rate-limiting threshold (suggested max 3 concurrent offers — needs validation with real courier behavior data)",
      "Redis Sentinel failover behavior under the specific bid window re-creation scenario — needs chaos testing"
    ],
    "assumptions": [
      "500 concurrent bid windows is a peak, not sustained — if sustained, Redis memory and sorted set polling remain well within bounds",
      "Courier mobile apps can maintain stable WebSocket connections (standard assumption for modern mobile networks)",
      "30 couriers per zone is an average — spikes to 100+ in popular zones would not change the architecture, only the fan-out volume",
      "The marketplace has an existing Order Management system that can publish OrderPlaced events",
      "Sub-second claim latency is acceptable (actual latency will be ~5-50ms depending on network between Gateway and Redis)"
    ]
  }
}

